import $ from 'jquery';
import View from 'local_activitylibrary/view';
import ViewNav from 'local_activitylibrary/view_nav';

/**
 * Activity Library entrypoint.
 */
export default class ActivityLibrary {
    /**
     * Initialise all modules for the Activity Library local plugin.
     *
     * @param {object} root The root element for the overview block.
     */
    static init(root) {
        const rootNode = $(root);
        ViewNav.init(rootNode);
        View.init(rootNode);
    }
}
